/**
 * 月份，包含年月
 *
 * @type {string}
 * @group Constant
 * @category Month
 * @example
 * 示例：2020-10
 */
export declare const MONTH_DEFAULT = "YYYY-MM";
/**
 * 月份，只有月
 *
 * @type {string}
 * @group Constant
 * @category Month
 * @example
 * 示例：10
 */
export declare const MONTH_ONLY = "MM";
/**
 * 月份，中文版年月
 *
 * @type {string}
 * @group Constant
 * @category Month
 * @example
 * 示例：2020年10月
 */
export declare const MONTH_CHINESE = "YYYY\u5E74M\u6708";
/**
 * 月份，中文版只有月
 *
 * @type {string}
 * @group Constant
 * @category Month
 * @example
 * 示例：10月
 */
export declare const MONTH_ONLY_CHINESE = "M\u6708";
